"use client"

import { useState, useEffect, useCallback, useMemo } from 'react';
import { generateAISignal, AISignalOutput } from '@/ai/flows/ai-signal-generation';
import { useUser, useFirestore } from '@/firebase';
import { doc, getDoc, updateDoc, setDoc, collection, addDoc, serverTimestamp } from 'firebase/firestore';

const FREE_LIMIT = 7;
const SUBSCRIPTION_DAYS = 30;

export const useTradingSignals = () => {
  const { user } = useUser();
  const db = useFirestore();
  const [signalCount, setSignalCount] = useState(0);
  const [isPaywallOpen, setIsPaywallOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [signals, setSignals] = useState<Record<string, AISignalOutput | null>>({});
  const [isVip, setIsVip] = useState(false);
  const [isSyncing, setIsSyncing] = useState(true);

  // Memoize the sync function to prevent dependency loops
  const syncStatus = useCallback(async () => {
    if (!user || !db) {
      setIsSyncing(false);
      return;
    }

    const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
    try {
      const snap = await getDoc(profileRef);
      
      if (snap.exists()) {
        const data = snap.data();
        let currentIsSubscribed = data.isSubscribed || false;
        
        // Subscription expiry logic
        if (currentIsSubscribed && data.subscriptionStartDate) {
          const startDate = new Date(data.subscriptionStartDate).getTime();
          const thirtyDaysInMs = SUBSCRIPTION_DAYS * 24 * 60 * 60 * 1000;
          if (Date.now() > startDate + thirtyDaysInMs) {
            currentIsSubscribed = false;
            updateDoc(profileRef, { 
              isSubscribed: false,
              updatedAt: new Date().toISOString()
            });
          }
        }

        setSignalCount(data.freeSignalsUsedCount || 0);
        setIsVip(currentIsSubscribed);
      } else {
        const initialData = {
          id: user.uid,
          email: user.email,
          name: user.displayName || 'Institutional Trader',
          isSubscribed: false,
          freeSignalsUsedCount: 0,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          subscriptionStartDate: null
        };
        await setDoc(profileRef, initialData);
        setSignalCount(0);
        setIsVip(false);
      }
    } catch (error) {
      console.error("Firestore sync error:", error);
    } finally {
      setIsSyncing(false);
    }
  }, [user, db]);

  useEffect(() => {
    syncStatus();
  }, [syncStatus]);

  const fetchSignal = useCallback(async (symbol: string, type: 'Forex' | 'Crypto') => {
    if (isSyncing || loading) return;

    if (!isVip && signalCount >= FREE_LIMIT) {
      setIsPaywallOpen(true);
      return;
    }

    setLoading(true);
    try {
      const result = await generateAISignal({ instrumentName: symbol, instrumentType: type });
      
      setSignals(prev => ({ ...prev, [symbol]: result }));
      
      const newCount = signalCount + 1;
      setSignalCount(newCount);

      if (user && db) {
        const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
        updateDoc(profileRef, { 
          freeSignalsUsedCount: newCount,
          updatedAt: new Date().toISOString()
        });

        // Add to history (non-blocking for better UX)
        const historyRef = collection(db, 'users', user.uid, 'signalHistory');
        addDoc(historyRef, {
          symbol,
          type,
          ...result,
          viewedAt: serverTimestamp(),
          pipsResult: Math.floor(Math.random() * 100) - 20
        });
      }
      
      if (!isVip && newCount >= FREE_LIMIT) {
        setIsPaywallOpen(true);
      }
    } catch (error) {
      console.error("Signal execution error:", error);
    } finally {
      setLoading(false);
    }
  }, [signalCount, isVip, user, db, isSyncing, loading]);

  return {
    signalCount,
    isPaywallOpen,
    setIsPaywallOpen,
    loading,
    signals,
    fetchSignal,
    freeLimit: FREE_LIMIT,
    isVip,
    isSyncing
  };
};